/**
 * Handles the gnosis encode Monster Number Projection workflow.
 */
export function encodeMonsterNumberProjection(): MonsterNumberProjection {
  return buildProtocol69ProjectionEnvelope();
}

/**
 * Builds the Protocol69 Foil Admission Certificate.
 */
export function buildProtocol69FoilAdmissionCertificate(
  report?: Protocol69FoilProbeReport,
): Protocol69FoilAdmissionCertificate | undefined {
  if (!report) {
    return undefined;
  }

  return {
    certificateVersion: PROTOCOL69_FOIL_ADMISSION_CERTIFICATE_VERSION,
    protocol: 'protocol69',
    wordName: 'sixty9',
    source: 'monster-rf-cache-key',
    projectionAccepted: report.ok,
    requiredTransport: report.transport,
    httpAccepted: report.http?.ok,
    flowUdpAccepted: report.flowUdp?.ok,
    broadcastSymbol: 66,
    localFoilOperand: 7,
    expectedProjection: 69,
    theoremRefs: [
      'Gnosis.RemoteCacheKeyTeleportation.protocol69_monster_number_projection',
      'Gnosis.RemoteCacheKeyTeleportation.protocol69_braids_integer_projection_with_fano_parity',
    ],
  };
}

function validateProtocol69ProjectionResponse(body: unknown): string | null {
  if (typeof body !== 'object' || body === null || !('projection' in body)) {
    return 'response missing projection';
  }
  const projection = (body as { readonly projection?: unknown }).projection;
  if (typeof projection !== 'object' || projection === null) {
    return 'response projection is not an object';
  }
  const record = projection as Partial<MonsterNumberProjection>;
  if (record.protocol !== 'protocol69') return 'protocol mismatch';
  if (record.wordName !== 'sixty9') return 'wordName mismatch';
  if (record.broadcastSymbol !== 66) return 'broadcastSymbol mismatch';
  if (record.localFoilOperand !== 7) return 'localFoilOperand mismatch';
  if (record.expectedProjection !== 69) return 'expectedProjection mismatch';
  return null;
}

function encodeFlowFrame(payload: string, sequence = 0): Buffer {
  const payloadBytes = Buffer.from(payload);
  if (payloadBytes.length > 0x00ff_ffff) {
    throw new Error('payload exceeds 24-bit Aeon Flow frame length');
  }
  const frame = Buffer.alloc(FLOW_HEADER_SIZE + payloadBytes.length);
  frame.writeUInt16BE(1, 0);
  frame.writeUInt32BE(sequence, 2);
  frame[6] = FLOW_FLAGS_FORK_RACE_FOLD_VENT;
  frame[7] = (payloadBytes.length >> 16) & 0xff;
  frame[8] = (payloadBytes.length >> 8) & 0xff;
  frame[9] = payloadBytes.length & 0xff;
  payloadBytes.copy(frame, FLOW_HEADER_SIZE);
  return frame;
}

function decodeFlowFramePayload(bytes: Buffer): string {
  if (bytes.length < FLOW_HEADER_SIZE) {
    throw new Error('buffer smaller than Aeon Flow header');
  }
  const payloadLength = (bytes[7]! << 16) | (bytes[8]! << 8) | bytes[9]!;
  if (bytes.length < FLOW_HEADER_SIZE + payloadLength) {
    throw new Error('incomplete Aeon Flow payload');
  }
  return bytes.subarray(FLOW_HEADER_SIZE, FLOW_HEADER_SIZE + payloadLength).toString('utf8');
}

function parseJsonMaybe(text: string): unknown {
  if (text.trim() === '') return '';
  try {
    return JSON.parse(text) as unknown;
  } catch {
    return text;
  }
}

/**
 * Handles the gnosis probe Protocol69 Foil Http workflow.
 */
export async function probeProtocol69FoilHttp(
  url: string,
  timeoutMs: number,
): Promise<Protocol69FoilProbeLeg> {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(encodeMonsterNumberProjection()),
      signal: controller.signal,
    });
    const body = parseJsonMaybe(await response.text());
    const validationError = response.ok ? validateProtocol69ProjectionResponse(body) : null;
    return {
      attempted: true,
      ok: response.ok && validationError === null,
      status: response.status,
      endpoint: url,
      response: body,
      error: validationError ?? undefined,
    };
  } catch (error) {
    return {
      attempted: true,
      ok: false,
      status: null,
      endpoint: url,
      error: error instanceof Error ? error.message : String(error),
    };
  } finally {
    clearTimeout(timeout);
  }
}

/**
 * Handles the gnosis probe Protocol69 Foil Flow Udp workflow.
 */
export async function probeProtocol69FoilFlowUdp(opts: {
  readonly host: string;
  readonly port: number;
  readonly path: string;
  readonly timeoutMs: number;
}): Promise<Protocol69FoilProbeLeg> {
  const endpoint = `aeon://${opts.host}:${opts.port}${opts.path}`;
  const socket = dgram.createSocket('udp4');
  try {
    const frame = encodeFlowFrame(opts.path);
    const response = await new Promise<Buffer>((resolve, reject) => {
      const timeout = setTimeout(() => {
        reject(new Error(`Flow/UDP timeout after ${opts.timeoutMs}ms`));
      }, opts.timeoutMs);
      socket.once('message', (message: Buffer) => {
        clearTimeout(timeout);
        resolve(message);
      });
      socket.once('error', (error: Error) => {
        clearTimeout(timeout);
        reject(error);
      });
      socket.send(frame, opts.port, opts.host);
    });
    const body = parseJsonMaybe(decodeFlowFramePayload(response));
    const validationError = validateProtocol69ProjectionResponse(body);
    return {
      attempted: true,
      ok: validationError === null,
      status: validationError === null ? 200 : 502,
      endpoint,
      response: body,
      error: validationError ?? undefined,
    };
  } catch (error) {
    return {
      attempted: true,
      ok: false,
      status: null,
      endpoint,
      error: error instanceof Error ? error.message : String(error),
    };
  } finally {
    socket.close();
  }
}

/**
 * Handles the gnosis probe Protocol69 Foil workflow.
 */
export async function probeProtocol69Foil(
  config: Protocol69FoilProbeConfig,
): Promise<Protocol69FoilProbeReport> {
  const http =
    config.transport === 'http' || config.transport === 'both'
      ? await probeProtocol69FoilHttp(config.url, config.timeoutMs)
      : undefined;
  const flowUdp =
    config.transport === 'flow-udp' || config.transport === 'both'
      ? await probeProtocol69FoilFlowUdp({
          host: config.flowHost,
          port: config.flowPort,
          path: config.flowPath,
          timeoutMs: config.timeoutMs,
        })
      : undefined;
  return {
    protocol: 'protocol69',
    transport: config.transport,
    ok: (http?.ok ?? true) && (flowUdp?.ok ?? true),
    http,
    flowUdp,
  };
}

