/**
 * Handles the gnosis crc16 Ccitt Ascii workflow.
 */
export function crc16CcittAscii(input: string): number {
  let crc = 0xffff;
  for (let i = 0; i < input.length; i++) {
    crc ^= input.charCodeAt(i) << 8;
    for (let bit = 0; bit < 8; bit++) {
      crc = (crc & 0x8000) !== 0 ? ((crc << 1) ^ 0x1021) : (crc << 1);
      crc &= 0xffff;
    }
  }
  return crc;
}

/**
 * Handles the gnosis encode Rf Cache Key Frame workflow.
 */
export function encodeRfCacheKeyFrame(packet: RfCacheKeyPacket): RfCacheKeyFrame {
  const body = [
    RF_CACHE_KEY_FRAME_MAGIC,
    `prefixHash=${packet.prefixHash}`,
    `prefixLen=${packet.prefixLen}`,
    `boundaryDimension=${packet.boundaryDimension}`,
    `stationCount=${packet.stationCount}`,
  ].join(' ');
  const crc16 = crc16CcittAscii(body);
  return {
    magic: RF_CACHE_KEY_FRAME_MAGIC,
    packet,
    crc16,
    ascii: `${body} crc16=${crc16.toString(16).padStart(4, '0')}`,
  };
}

/**
 * Handles the gnosis encode Protocol69 App Cache Key Frame workflow.
 */
export function encodeProtocol69AppCacheKeyFrame(
  receipt: Protocol69AppCacheKeyReceiptLike,
): Protocol69AppCacheKeyFrame {
  const parts = [
    PROTOCOL69_APP_CACHE_KEY_FRAME_MAGIC,
    `schema=${receipt.schemaVersion}`,
    `cacheKey=${receipt.computeCacheKey}`,
  ];
  if (receipt.keyMaterial.functionName) {
    parts.push(`function=${receipt.keyMaterial.functionName}`);
  }
  if (receipt.keyMaterial.programChecksum) {
    parts.push(`programChecksum=${receipt.keyMaterial.programChecksum}`);
  }
  const body = parts.join(' ');
  const crc16 = crc16CcittAscii(body);
  return {
    magic: PROTOCOL69_APP_CACHE_KEY_FRAME_MAGIC,
    receiptSchemaVersion: receipt.schemaVersion,
    computeCacheKey: receipt.computeCacheKey,
    programChecksum: receipt.keyMaterial.programChecksum,
    functionName: receipt.keyMaterial.functionName,
    crc16,
    ascii: `${body} crc16=${crc16.toString(16).padStart(4, '0')}`,
  };
}

/**
 * Builds the Protocol69 App Cache Key Transmission.
 */
export function buildProtocol69AppCacheKeyTransmission(
  receipt: Protocol69AppCacheKeyReceiptLike,
): Protocol69AppCacheKeyTransmission {
  if (receipt.receiptReturn !== 'compute-cache-key') {
    throw new Error('protocol69 app receipt must return compute-cache-key');
  }
  if (!receipt.computeCacheKey.startsWith('gnosis:protocol69:polyglot-app-cache:v1:')) {
    throw new Error('protocol69 app receipt has an unsupported compute cache key prefix');
  }
  return {
    receipt,
    frame: encodeProtocol69AppCacheKeyFrame(receipt),
  };
}

/**
 * Parses the Rtl Test Devices.
 */
export function parseRtlTestDevices(stderr: string): RtlSdrDevice[] {
  const devices: RtlSdrDevice[] = [];
  const re = /^\s*(\d+):\s*([^,]+),\s*([^,]+),\s*SN:\s*(\S+)\s*$/gm;
  let match: RegExpExecArray | null;
  while ((match = re.exec(stderr)) !== null) {
    devices.push({
      index: Number.parseInt(match[1]!, 10),
      vendor: match[2]!.trim(),
      product: match[3]!.trim(),
      serial: match[4]!.trim(),
    });
  }
  return devices;
}

/**
 * Handles the gnosis probe Rtl Sdr workflow.
 */
export function probeRtlSdr(binary = 'rtl_test'): RtlSdrProbe {
  const result = spawnSync(binary, ['-t'], {
    encoding: 'utf8',
    timeout: 10_000,
  });
  const stderr = `${result.stderr ?? ''}${result.stdout ?? ''}`;
  const devices = parseRtlTestDevices(stderr);
  return {
    binary,
    devices,
    healthy: (result.status ?? 1) === 0 && devices.length > 0,
    status: result.status,
    stderr,
  };
}

/**
 * Handles the gnosis capture Rtl Sdr Window workflow.
 */
export function captureRtlSdrWindow(
  config: RtlSdrCaptureConfig,
): RtlSdrCaptureResult {
  const outputPath = resolve(config.outputPath);
  mkdirSync(dirname(outputPath), { recursive: true });
  const argv = [
    '-f',
    String(config.centerFrequencyHz),
    '-s',
    String(config.sampleRateHz),
    '-n',
    String(config.samplePairs),
  ];
  if (config.deviceIndex && config.deviceIndex.trim() !== '') {
    argv.push('-d', config.deviceIndex);
  }
  argv.push(outputPath);
  const result = spawnSync(config.binary, argv, {
    encoding: 'utf8',
    timeout: 30_000,
  });
  const statusOk = (result.status ?? 1) === 0;
  let byteLength: number | undefined;
  let energy: RtlSdrEnergyStats | undefined;
  if (statusOk) {
    try {
      byteLength = statSync(outputPath).size;
      energy = analyzeRtlU8Energy(readFileSync(outputPath));
    } catch {
      byteLength = undefined;
      energy = undefined;
    }
  }
  const expectedBytes = config.samplePairs * 2;
  const ok = statusOk && byteLength === expectedBytes;
  return {
    attempted: true,
    binary: config.binary,
    argv,
    outputPath,
    centerFrequencyHz: config.centerFrequencyHz,
    sampleRateHz: config.sampleRateHz,
    samplePairs: config.samplePairs,
    ok,
    status: result.status,
    stdout: result.stdout ?? '',
    stderr: result.stderr ?? '',
    byteLength,
    energy,
    capturedAtIso: new Date().toISOString(),
    error: result.error?.message,
  };
}

/**
 * Handles the gnosis analyze Rtl U8 Energy workflow.
 */
export function analyzeRtlU8Energy(iqU8: Uint8Array): RtlSdrEnergyStats {
  if (iqU8.length < 2 || iqU8.length % 2 !== 0) {
    return {
      iqPairs: 0,
      meanI: 0,
      meanQ: 0,
      meanMagnitudeSquared: 0,
      rmsMagnitude: 0,
      peakMagnitude: 0,
      dcOffsetMagnitude: 0,
      energyDetected: false,
    };
  }
  const iqPairs = iqU8.length / 2;
  let sumI = 0;
  let sumQ = 0;
  let sumMag2 = 0;
  let peakMag2 = 0;
  for (let p = 0; p + 1 < iqU8.length; p += 2) {
    const i = (iqU8[p]! - 128) / 128;
    const q = (iqU8[p + 1]! - 128) / 128;
    const mag2 = i * i + q * q;
    sumI += i;
    sumQ += q;
    sumMag2 += mag2;
    if (mag2 > peakMag2) peakMag2 = mag2;
  }
  const meanI = sumI / iqPairs;
  const meanQ = sumQ / iqPairs;
  const meanMagnitudeSquared = sumMag2 / iqPairs;
  const rmsMagnitude = Math.sqrt(meanMagnitudeSquared);
  const peakMagnitude = Math.sqrt(peakMag2);
  const dcOffsetMagnitude = Math.sqrt(meanI * meanI + meanQ * meanQ);
  return {
    iqPairs,
    meanI,
    meanQ,
    meanMagnitudeSquared,
    rmsMagnitude,
    peakMagnitude,
    dcOffsetMagnitude,
    energyDetected: rmsMagnitude > 0.02 || peakMagnitude > 0.08,
  };
}

/**
 * Handles the gnosis infer External Tx Kind workflow.
 */
export function inferExternalTxKind(binary: string): ExternalTxKind {
  const lower = binary.toLowerCase();
  if (lower.includes('hackrf_transfer')) return 'hackrf-transfer';
  if (lower.includes('soapysdr')) return 'soapy-sdr-tx';
  return 'executable-stdin';
}

/**
 * Handles the gnosis probe Soapy Sdr Device workflow.
 */
export function probeSoapySdrDevice(
  binary: string,
  deviceArgs: string,
): ExternalTxDiscovery {
  const argv = deviceArgs.trim() === '' ? ['--find'] : [`--find=${deviceArgs}`];
  const result = spawnSync(binary, argv, {
    encoding: 'utf8',
    timeout: 10_000,
  });
  const stdout = result.stdout ?? '';
  const stderr = result.stderr ?? '';
  const combined = `${stdout}\n${stderr}`.toLowerCase();
  const hardwarePresent =
    (result.status ?? 1) === 0 &&
    combined.trim() !== '' &&
    !combined.includes('no devices found') &&
    !combined.includes('found device(s): 0');
  return {
    attempted: true,
    binary,
    argv,
    hardwarePresent,
    status: result.status,
    stdout,
    stderr,
    error: result.error?.message,
  };
}

/**
 * Builds the External Tx Adapter.
 */
export function buildExternalTxAdapter(
    config: ExternalTxConfig,
    stdinFrame: string,
    discovery?: ExternalTxDiscovery,
): ExternalTxAdapter {
  if (config.binary.trim() === '') {
    return {
      kind: config.kind,
      binary: config.binary,
      available: false,
      argv: [],
      centerFrequencyHz: config.centerFrequencyHz,
      sampleRateHz: config.sampleRateHz,
      gainDb: config.gainDb,
      reason: 'no transmitter binary configured',
      discovery,
    };
  }

  if (config.kind === 'hackrf-transfer') {
    if (!config.iqFile || config.iqFile.trim() === '') {
      return {
        kind: config.kind,
        binary: config.binary,
        available: false,
        argv: [],
        centerFrequencyHz: config.centerFrequencyHz,
        sampleRateHz: config.sampleRateHz,
        gainDb: config.gainDb,
        reason: 'hackrf_transfer requires a premodulated IQ file via --tx-iq-file or GNOSIS_RF_TX_IQ_FILE',
        discovery,
      };
    }
    return {
      kind: config.kind,
      binary: config.binary,
      available: true,
      argv: [
        '-t',
        config.iqFile,
        '-f',
        String(config.centerFrequencyHz),
        '-s',
        String(config.sampleRateHz),
        '-x',
        String(config.gainDb),
      ],
      centerFrequencyHz: config.centerFrequencyHz,
      sampleRateHz: config.sampleRateHz,
      gainDb: config.gainDb,
      discovery,
    };
  }

  if (config.kind === 'soapy-sdr-tx') {
    if (!config.deviceArgs || config.deviceArgs.trim() === '') {
      return {
        kind: config.kind,
        binary: config.binary,
        available: false,
        argv: [],
        centerFrequencyHz: config.centerFrequencyHz,
        sampleRateHz: config.sampleRateHz,
        gainDb: config.gainDb,
        reason: 'SoapySDR TX requires device arguments via --tx-device-args or GNOSIS_RF_TX_DEVICE_ARGS',
        discovery,
      };
    }
    if (discovery?.attempted === true && !discovery.hardwarePresent) {
      return {
        kind: config.kind,
        binary: config.binary,
        available: false,
        argv: [],
        centerFrequencyHz: config.centerFrequencyHz,
        sampleRateHz: config.sampleRateHz,
        gainDb: config.gainDb,
        reason: discovery.error ?? 'SoapySDR discovery did not find the requested transmitter',
        discovery,
      };
    }
    return {
      kind: config.kind,
      binary: config.binary,
      available: true,
      argv: [
        '--device',
        config.deviceArgs,
        '--rate',
        String(config.sampleRateHz),
        '--freq',
        String(config.centerFrequencyHz),
        '--gain',
        String(config.gainDb),
        '--stdin-ascii-frame',
      ],
      centerFrequencyHz: config.centerFrequencyHz,
      sampleRateHz: config.sampleRateHz,
      gainDb: config.gainDb,
      stdinFrame,
      discovery,
    };
  }

  return {
    kind: config.kind,
    binary: config.binary,
    available: true,
    argv: [
      '--center-frequency-hz',
      String(config.centerFrequencyHz),
      '--sample-rate-hz',
      String(config.sampleRateHz),
      '--gain-db',
      String(config.gainDb),
    ],
    centerFrequencyHz: config.centerFrequencyHz,
    sampleRateHz: config.sampleRateHz,
    gainDb: config.gainDb,
    stdinFrame,
    discovery,
  };
}

/**
 * Handles the gnosis execute External Tx Adapter workflow.
 */
export function executeExternalTxAdapter(
  adapter: ExternalTxAdapter,
): ExternalTxExecution {
  if (!adapter.available) {
    return {
      attempted: false,
      status: null,
      signal: null,
      stdout: '',
      stderr: adapter.reason ?? 'transmitter adapter is not available',
    };
  }
  const result = spawnSync(adapter.binary, [...adapter.argv], {
    encoding: 'utf8',
    input: adapter.stdinFrame,
    timeout: 30_000,
  });
  return {
    attempted: true,
    status: result.status,
    signal: result.signal,
    stdout: result.stdout ?? '',
    stderr: result.stderr ?? '',
  };
}

/**
 * Builds the Monster Rf Cache Key Envelope.
 */
export function buildMonsterRfCacheKeyEnvelope(opts: {
  readonly transport: 'simulated' | 'hardware';
  readonly rtlProbe?: RtlSdrProbe;
  readonly txBin?: string | null;
  readonly txKind?: ExternalTxKind | null;
  readonly txCenterFrequencyHz?: number;
  readonly txSampleRateHz?: number;
  readonly txGainDb?: number;
  readonly txIqFile?: string | null;
  readonly txDeviceArgs?: string | null;
  readonly txDiscovery?: ExternalTxDiscovery;
  readonly rxCapture?: RtlSdrCaptureResult;
  readonly symbolMode?: RfSymbolMode;
  readonly appTeleportReceipt?: Protocol69AppCacheKeyReceiptLike;
  readonly protocol69FoilProbe?: Protocol69FoilProbeReport;
}): MonsterRfCacheKeyEnvelope {
  const frame = encodeRfCacheKeyFrame(canonicalRfCacheKeyPacket);
  const projection =
    opts.symbolMode === 'monster-number' ? encodeMonsterNumberProjection() : undefined;
  const appTeleport =
    opts.symbolMode === 'polyglot-app-cache-key' && opts.appTeleportReceipt
      ? buildProtocol69AppCacheKeyTransmission(opts.appTeleportReceipt)
      : undefined;
  const stdinFrame = appTeleport?.frame.ascii ?? projection?.ascii ?? frame.ascii;
  const deviceSerials = opts.rtlProbe?.devices.map((d) => d.serial) ?? [];
  const txBin = opts.txBin?.trim() ?? '';
  const adapter =
    opts.transport === 'hardware' && txBin !== ''
      ? buildExternalTxAdapter(
          {
            kind: opts.txKind ?? inferExternalTxKind(txBin),
            binary: txBin,
            centerFrequencyHz:
              opts.txCenterFrequencyHz ?? defaultRfTxCenterFrequencyHz,
            sampleRateHz: opts.txSampleRateHz ?? defaultRfTxSampleRateHz,
            gainDb: opts.txGainDb ?? defaultRfTxGainDb,
            iqFile: opts.txIqFile ?? undefined,
            deviceArgs: opts.txDeviceArgs ?? undefined,
          },
          stdinFrame,
          opts.txDiscovery,
        )
      : undefined;
  const txAvailable = opts.transport === 'simulated' || (adapter?.available ?? false);
  const protocol69FoilAdmission = buildProtocol69FoilAdmissionCertificate(
    opts.protocol69FoilProbe,
  );
  return {
    monsterRfCacheKey: {
      schemaVersion: RF_CACHE_KEY_SCHEMA_VERSION,
      transport: opts.transport,
      broadcaster:
        opts.transport === 'simulated'
          ? { kind: 'simulated-baseband', txAvailable: true }
          : {
              kind: 'external-tx',
              txAvailable,
              reason: txAvailable
                ? undefined
                : adapter?.reason ??
                  'RTL-SDR devices are receive-only; set GNOSIS_RF_TX_BIN or --tx-bin for live RF transmit.',
              adapter,
            },
      receiver:
        opts.transport === 'simulated'
          ? { kind: 'simulated-baseband', deviceSerials: [], healthy: true }
          : {
              kind: 'rtl-sdr',
              deviceSerials,
              healthy: opts.rxCapture?.ok ?? opts.rtlProbe?.healthy ?? false,
              capture: opts.rxCapture,
            },
      frame,
      projection,
      appTeleport,
      protocol69FoilProbe: opts.protocol69FoilProbe,
      protocol69FoilAdmission,
      replayContract: {
        prefixHash: 66,
        prefixLen: 7,
        cachedReplay: true,
        geodesicLength: 0,
      },
    },
  };
}
